import java.util.*; public class Knight extends Piece { public Knight(PieceColor color){super(color);} @Override public char getSymbol(){return 'n';} @Override public List<Move> getLegalMoves(Position from, Board board){ List<Move> res=new ArrayList<>(); int[][] offs={{2,1},{2,-1},{-2,1},{-2,-1},{1,2},{1,-2},{-1,2},{-1,-2}}; for(int[] o:offs){ int r=from.row+o[0], c=from.col+o[1]; if(inBounds(r,c)){ Position to=new Position(r,c); Piece t=board.getPiece(to); if(t==null||t.getColor()!=color) res.add(new Move(from,to,this,t)); } } return res; } @Override public Piece copy(){ Knight p=new Knight(color); p.moved=this.moved; return p; } }